/** Class for a lazy cons structure (call-by-name: re-evaluates suspensions each time). */
static class JamLazyNameCons extends JamCons {
  /** Suspension for first */
  protected Suspension firstSusp;
  /** Suspension for rest */
  protected Suspension restSusp;

  public JamLazyNameCons(Suspension first, Suspension rest) {
    super(null, null);  // underlying fields unused; we override first() and rest()
    firstSusp = first;
    restSusp = rest;
  }

  /** Forces and returns the first element of this lazy cons (re-evaluated each call). */
  public JamVal first() { return firstSusp.eval(); }

  /** Forces and returns the rest of this lazy cons as a JamList (re-evaluated each call). */
  public JamList rest() {
    JamVal val = restSusp.eval();
    return JamCons.checkList(val);
  }
}

/** Class for a lazy cons with call-by-need optimization (caches forced values). */
static class JamLazyNeedCons extends JamLazyNameCons {
  /** Cached value of first (null until forced). */
  private JamVal cachedFirst = null;
  /** Cached value of rest (null until forced). */
  private JamList cachedRest = null;

  public JamLazyNeedCons(Suspension first, Suspension rest) { super(first, rest); }

  /** Forces the first suspension on first access, then returns cached value. */
  public JamVal first() {
    if (cachedFirst == null) cachedFirst = firstSusp.eval();
    return cachedFirst;
  }

  /** Forces the rest suspension on first access, then returns cached JamList. */
  public JamList rest() {
    if (cachedRest == null) cachedRest = JamCons.checkList(restSusp.eval());
    return cachedRest;
  }
}

