/** Implements recursive let: each RHS is evaluated in the extended environment that includes all let-bound vars.
  * For call-by-value, each RHS is evaluated eagerly in left-to-right order; forward references throw EvalException.
  * For call-by-name and call-by-need, RHS evaluation is deferred via suspensions, enabling mutual recursion. */
public JamVal forLet(Let l) {
  Variable[] vars = l.vars();
  AST[] exps = l.exps();
  int n = vars.length;

  /* Step 1: Create dummy bindings for all vars and build the recursive environment. */
  Binding[] bindings = new Binding[n];
  PureList<Binding> newEnv = env();
  for (int i = 0; i < n; i++) {
    bindings[i] = bindingPolicy.newDummyBinding(vars[i]);
    newEnv = newEnv.cons(bindings[i]);
  }

  /* Step 2: Create new EvalVisitor with the recursive environment. */
  EvalVisitor newEV = newEvalVisitor(newEnv);

  /* Step 3: Update each dummy binding with the RHS evaluated in the recursive environment.
   * For CBV, setBinding evaluates immediately (left-to-right); for CBName/CBNeed, defers via suspension. */
  for (int i = 0; i < n; i++) {
    bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));
  }

  return l.body().accept(newEV);
}

