/** A visitor class for the syntax checker. Returns normally unless there is a syntax error. On a syntax error,
  * throws a SyntaxException.
  */
class CheckVisitor implements ASTVisitor<Void> {

  /** Empty symbol table. */
  private static final Empty<Variable> EMPTY_VARS = new Empty<Variable>();

  /** Symbol table to detect free variables. Variables in scope are listed here. */
  PureList<Variable> env;

  /** Root form of CheckVisitor with empty (top-level) environment. */
  public static final CheckVisitor INITIAL = new CheckVisitor(EMPTY_VARS);

  CheckVisitor(PureList<Variable> e) { env = e; }

  /** Returns a new CheckVisitor with the given variables added to the environment. */
  private CheckVisitor extend(Variable[] vars) {
    PureList<Variable> newEnv = env;
    for (Variable v : vars) newEnv = newEnv.cons(v);
    return new CheckVisitor(newEnv);
  }

  /** Checks that a list of variables has no duplicates; throws SyntaxException if it does. */
  private void checkNoDuplicates(Variable[] vars, String context) {
    PureList<Variable> seen = EMPTY_VARS;
    for (Variable v : vars) {
      if (seen.contains(v)) throw new SyntaxException("Duplicate variable `" + v + "' in " + context);
      seen = seen.cons(v);
    }
  }

  /* ASTVisitor methods. */
  public Void forBoolConstant(BoolConstant b) { return null; }
  public Void forIntConstant(IntConstant i) { return null; }
  public Void forEmptyConstant(EmptyConstant n) { return null; }

  /** Checks that the variable is bound in the current environment; throws SyntaxException if free. */
  public Void forVariable(Variable v) {
    if (env.accept(new LookupVisitor<Variable>(v)) == null)
      throw new SyntaxException("Free variable `" + v + "'");
    return null;
  }

  public Void forPrimFun(PrimFun f) { return null; }

  public Void forUnOpApp(UnOpApp u) { u.arg().accept(this); return null; }

  public Void forBinOpApp(BinOpApp b) { b.arg1().accept(this); b.arg2().accept(this); return null; }

  public Void forApp(App a) {
    a.rator().accept(this);
    for (AST arg : a.args()) arg.accept(this);
    return null;
  }

  /** Checks for duplicate parameters then checks body in extended environment. */
  public Void forMap(Map m) {
    Variable[] vars = m.vars();
    checkNoDuplicates(vars, "map parameter list");
    m.body().accept(extend(vars));
    return null;
  }

  public Void forIf(If i) { i.test().accept(this); i.conseq().accept(this); i.alt().accept(this); return null; }

  /** Checks for duplicate let-bound names; checks all RHSs and the body in the extended (recursive) environment. */
  public Void forLet(Let l) {
    Variable[] vars = l.vars();
    checkNoDuplicates(vars, "let binding");
    CheckVisitor newCV = extend(vars);
    for (AST exp : l.exps()) exp.accept(newCV);
    l.body().accept(newCV);
    return null;
  }
}

/** Visitor that checks a PureList<Variable> for duplicate entries. Throws SyntaxException on first duplicate found. */
class AnyDuplicatesVisitor implements PureListVisitor<Variable, Void> {
  /** Checks whether the head of the list already appears in the tail; recurses on the tail. */
  public Void forEmpty(Empty<Variable> e) { return null; }
  public Void forCons(Cons<Variable> c) {
    Variable first = c.first();
    if (c.rest().contains(first))
      throw new SyntaxException("Duplicate variable `" + first + "' in parameter/binding list");
    return c.rest().accept(this);
  }
}

